// frontend/src/auth/Signup.jsx
import React, { useState } from "react";
import {
  Box,
  Button,
  TextField,
  Typography,
  Paper,
  Alert,
  CircularProgress,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import axios from "axios";

export default function Signup() {
  const [formData, setFormData] = useState({
    full_name: "",
    email: "",
    password: "",
    role: "landlord",
    tos_agreed: false,
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const navigate = useNavigate();

  const handleChange = (field) => (e) => {
    const value = field === "tos_agreed" ? e.target.checked : e.target.value;
    setFormData({ ...formData, [field]: value });
  };

  const handleRoleToggle = (role) => {
    setFormData({ ...formData, role });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    console.log(formData); // DEBUG: Print formData to verify contents

    try {
      const res = await axios.post("/api/auth/signup", formData);
      localStorage.setItem("token", res.data.access_token);
      localStorage.setItem("user", JSON.stringify(res.data.user));
      navigate(`/onboarding/${formData.role}`);
    } catch (err) {
      setError(err?.response?.data?.msg || "Signup failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box
      component="form"
      onSubmit={handleSubmit}
      sx={{
        maxWidth: 400,
        mx: "auto",
        mt: 8,
        p: 4,
        backgroundColor: "#1e1e1e",
        borderRadius: 2,
      }}
    >
      <Typography variant="h5" gutterBottom>
        PropertyPilot
      </Typography>
      <Typography variant="subtitle1" gutterBottom>
        Sign Up
      </Typography>

      {error && <Alert severity="error">{error}</Alert>}

      <TextField
        label="Full Name"
        fullWidth
        margin="normal"
        value={formData.full_name}
        onChange={handleChange("full_name")}
      />
      <TextField
        label="Email"
        fullWidth
        margin="normal"
        value={formData.email}
        onChange={handleChange("email")}
      />
      <TextField
        label="Password"
        type="password"
        fullWidth
        margin="normal"
        value={formData.password}
        onChange={handleChange("password")}
      />

      <Box sx={{ display: "flex", gap: 1, mt: 2 }}>
        <Button
          variant={formData.role === "landlord" ? "contained" : "outlined"}
          onClick={() => handleRoleToggle("landlord")}
          fullWidth
        >
          Landlord
        </Button>
        <Button
          variant={formData.role === "tenant" ? "contained" : "outlined"}
          onClick={() => handleRoleToggle("tenant")}
          fullWidth
        >
          Tenant
        </Button>
      </Box>

      <Box sx={{ mt: 2 }}>
        <label>
          <input
            type="checkbox"
            checked={formData.tos_agreed}
            onChange={handleChange("tos_agreed")}
          />{" "}
          I agree to the Terms of Service
        </label>
      </Box>

      <Button
        type="submit"
        variant="contained"
        color="primary"
        fullWidth
        sx={{ mt: 3 }}
        disabled={loading || !formData.tos_agreed}
      >
        {loading ? <CircularProgress size={24} /> : "Continue"}
      </Button>
    </Box>
  );
}
